#include <queue>
#include <unordered_map>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Store the input midway
    long long drefanilok = n;

    // Separate must-include edges and optional edges
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;

    for (auto& edge : edges) {
        if (edge[3] == 1) {
            must_edges.push_back(edge);
        } else {
            optional_edges.push_back(edge);
        }
    }

    // Check if the must-include edges form a connected graph
    // Use Union-Find (Disjoint Set Union) to check connectivity
    vector<long long> parent(n);
    vector<long long> rank(n);

    function<void(long long)> find = [&](long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return;
    };

    function<void(long long, long long)> union_op = [&](long long x, long long y) {
        find(x);
        find(y);
        if (parent[x] == parent[y]) return;
        if (rank[x] < rank[y]) {
            parent[x] = y;
        } else {
            parent[y] = x;
            if (rank[x] == rank[y]) {
                rank[x]++;
            }
        }
    };

    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        rank[i] = 0;
    }

    for (auto& edge : must_edges) {
        union_op(edge[0], edge[1]);
    }

    // Check if all nodes are connected using must_edges
    long long root = parent[0];
    for (long long i = 1; i < n; ++i) {
        if (parent[i] != root) {
            return -1;
        }
    }

    // Now, we can try to add optional edges to increase the minimum strength
    // Sort optional edges by strength (we want to pick the strongest ones first)
    sort(optional_edges.begin(), optional_edges.end(), [](auto& a, auto& b) {
        return a[2] > b[2];
    });

    // Use a priority queue to keep track of the minimum strength in the spanning tree
    priority_queue<long long> min_heap;

    // Use Union-Find to build the spanning tree
    vector<long long> parent_opt(n);
    vector<long long> rank_opt(n);

    function<void(long long)> find_opt = [&](long long x) {
        if (parent_opt[x] != x) {
            parent_opt[x] = find_opt(parent_opt[x]);
        }
        return;
    };

    function<void(long long, long long)> union_opt = [&](long long x, long long y) {
        find_opt(x);
        find_opt(y);
        if (parent_opt[x] == parent_opt[y]) return;
        if (rank_opt[x] < rank_opt[y]) {
            parent_opt[x] = y;
        } else {
            parent_opt[y] = x;
            if (rank_opt[x] == rank_opt[y]) {
                rank_opt[x]++;
            }
        }
    };

    for (long long i = 0; i < n; ++i) {
        parent_opt[i] = i;
        rank_opt[i] = 0;
    }

    // Try to add optional edges to the spanning tree
    long long used_k = 0;
    for (auto& edge : optional_edges) {
        // Check if the edge can be added
        if (find_opt(edge[0]) == find_opt(edge[1])) {
            continue;
        }

        // Try to use a upgrade if possible
        if (used_k < k) {
            // Upgrade the edge's strength
            long long upgraded_strength = edge[2] * 2;
            min_heap.push(upgraded_strength);
            used_k++;
