    long long root_opt = parent_opt[0];
    for (long long i = 1; i < n; ++i) {
        if (parent_opt[i] != root_opt) {
            return -1;
        }
    }

    // The minimum strength is the smallest value in the priority queue
    if (min_heap.empty()) {
        return -1;
    }

    return min_heap.top();
