        if (edge[3] === 1) {
            mustEdges.push(edge);
        } else {
            optionalEdges.push(edge);
        }
    }

    // Check if the must-include edges form a connected graph
    // Use Union-Find (Disjoint Set Union) to check connectivity
    const parent: number[] = Array(n).fill(0).map((_, i) => i);
    const rank: number[] = Array(n).fill(0);

    function find(x: number): number {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x: number, y: number): void {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX === rootY) return;
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else {
            parent[rootY] = rootX;
            if (rank[rootX] === rank[rootY]) {
                rank[rootX]++;
            }
        }
    }

