    const root = find(0);
    for (let i = 1; i < n; ++i) {
        if (find(i) !== root) {
            return -1;
        }
    }

    // Now, we can try to add optional edges to increase the minimum strength
    // Sort optional edges by strength (we want to pick the strongest ones first)
    optionalEdges.sort((a, b) => b[2] - a[2]);

    // Use Union-Find to build the spanning tree
    const parentOpt: number[] = Array(n).fill(0).map((_, i) => i);
    const rankOpt: number[] = Array(n).fill(0);

    function findOpt(x: number): number {
        if (parentOpt[x] !== x) {
            parentOpt[x] = findOpt(parentOpt[x]);
        }
        return parentOpt[x];
    }

    function unionOpt(x: number, y: number): void {
        const rootX = findOpt(x);
        const rootY = findOpt(y);
        if (rootX === rootY) return;
        if (rankOpt[rootX] < rankOpt[rootY]) {
            parentOpt[rootX] = rootY;
        } else {
            parentOpt[rootY] = rootX;
            if (rankOpt[rootX] === rankOpt[rootY]) {
                rankOpt[rootX]++;
            }
        }
    }

    let usedK = 0;
    const minHeap: number[] = [];

    for (const edge of optionalEdges) {
        // Check if the edge can be added
        if (findOpt(edge[0]) === findOpt(edge[1])) {
            continue;
        }

        // Try to use a upgrade if possible
        if (usedK < k) {
            // Upgrade the edge's strength
            const upgradedStrength = edge[2] * 2;
            minHeap.push(upgradedStrength);
            usedK++;
        } else {
            // Cannot upgrade, so add the original strength
            minHeap.push(edge[2]);
        }

        unionOpt(edge[0], edge[1]);
    }

    // Check if the spanning tree is complete
    const rootOpt = findOpt(0);
    for (let i = 1; i < n; ++i) {
        if (findOpt(i) !== rootOpt) {
            return -1;
        }
    }

    // The minimum strength is the smallest value in the priority queue
    if (minHeap.length === 0) {
        return -1;
    }

    return Math.min(...minHeap);
}
